concept_explanation.lru_cache:
**LRU Cache — HashMap + Doubly Linked List:**

```java
class LRUCache {
    // Doubly linked list node:
    class Node { int key, val; Node prev, next; Node(int k,int v){key=k;val=v;} }
    Map<Integer,Node> map = new HashMap<>(); // key → node
    Node head=new Node(0,0), tail=new Node(0,0); // dummy sentinels
    int cap;
    LRUCache(int capacity){
        cap=capacity;
        head.next=tail; tail.prev=head; // empty list: head⟷tail
    }
    // Move node to front (most recent):
    void moveToFront(Node node){
        remove(node); addFront(node);
    }
    void remove(Node node){
        node.prev.next=node.next; node.next.prev=node.prev;
    }
    void addFront(Node node){
        node.next=head.next; node.prev=head;
        head.next.prev=node; head.next=node;
    }
    int get(int key){
        if(!map.containsKey(key)) return -1;
        moveToFront(map.get(key)); return map.get(key).val;
    }
    void put(int key, int val){
        if(map.containsKey(key)){ map.get(key).val=val; moveToFront(map.get(key)); return; }
        if(map.size()==cap){ // evict LRU (tail.prev)
            map.remove(tail.prev.key); remove(tail.prev);
        }
        Node node=new Node(key,val); addFront(node); map.put(key,node);
    }
}
// O(1) get and put — HashMap for lookup, DLL for ordering
```

